using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_eb7b52c6f5e84fbb9715a4ca20e29ed5.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that hardcodes a logged-in user
/// and persists the auth state so the WebAssembly runtime can pick it up.
/// </summary>
public sealed class ServerAuthenticationStateProvider
    : ServerAuthenticationStateProvider<object>
{
    public ServerAuthenticationStateProvider(PersistentComponentState persistentState)
        : base(persistentState) { }
}

public class ServerAuthenticationStateProvider<TDummy>
    : RevalidatingServerAuthenticationStateProvider
{
    private readonly PersistentComponentState _persistentState;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    protected override TimeSpan RevalidationInterval => TimeSpan.FromMinutes(30);

    public ServerAuthenticationStateProvider(PersistentComponentState persistentState)
        : base(LoggerFactory.Create(_ => { }))
    {
        _persistentState = persistentState;
        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    protected override Task<bool> ValidateAuthenticationStateAsync(
        AuthenticationState authenticationState, CancellationToken cancellationToken)
        => Task.FromResult(true);

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
    {
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, "HardcodedAuth");
        var user = new ClaimsPrincipal(identity);
        return Task.FromResult(new AuthenticationState(user));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? GetAuthenticationStateAsync();
        var state = await authState;
        var principal = state.User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            var userInfo = new UserInfo
            {
                Name = principal.FindFirst(ClaimTypes.Name)?.Value ?? "",
                Email = principal.FindFirst(ClaimTypes.Email)?.Value ?? "",
                Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
            };

            _persistentState.PersistAsJson(nameof(UserInfo), userInfo);
        }
    }

    protected override void Dispose(bool disposing)
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
        base.Dispose(disposing);
    }
}

